pub const HTTP_EXECUTOR_BASE_FEE_WEI: u128 = 2_500_000_000_000;
pub const HTTP_EXECUTOR_FEE_PER_INPUT_BYTE_WEI: u128 = 350_000_000;
pub const HTTP_EXECUTOR_FEE_PER_OUTPUT_BYTE_WEI: u128 = 350_000_000;
pub const ASYNC_COMMITMENT_GAS_PER_INPUT_BYTE: u128 = 1;
pub const ASYNC_INCLUSION_GAS_PER_BYTE: u128 = 1;

pub fn http_executor_fee(input_len: usize, output_len: usize) -> U256 {
    let input_component = U256::from(HTTP_EXECUTOR_FEE_PER_INPUT_BYTE_WEI) * U256::from(input_len as u64);
    let output_component = U256::from(HTTP_EXECUTOR_FEE_PER_OUTPUT_BYTE_WEI) * U256::from(output_len as u64);
    U256::from(HTTP_EXECUTOR_BASE_FEE_WEI) + input_component + output_component
}

pub fn async_commitment_fee(input_len: usize) -> U256 {
    let gas_units = U256::from(ASYNC_COMMITMENT_GAS_PER_INPUT_BYTE) * U256::from(input_len as u64);
    gas_units * U256::from(ASYNC_VALIDATION_GAS_PRICE_WEI)
}
pub fn async_inclusion_fee(_input_len: usize, _output_len: usize) -> U256 { U256::ZERO }
